import React, { useState, useEffect } from 'react';
import axios from 'axios';

const MicrosoftTeams = () => {
  const [contacts, setContacts] = useState([]);
  const [loadingContacts, setLoadingContacts] = useState(false);
  const [accessToken, setAccessToken] = useState(null);
  const [noContactsMessage, setNoContactsMessage] = useState('');

  // Funcție pentru redirecționarea utilizatorului la backend pentru login
  const handleLogin = () => {
    window.location.href = 'http://localhost:8000/shortcuts/teams/login/';
  };

  // Funcție pentru a obține token-ul din callback-ul backend-ului
  const handleCallback = async () => {
    try {
      const response = await axios.get('http://localhost:8000/shortcuts/teams/callback/');
      const token = response.data.access_token;
      console.log('Token de acces:', token);
      setAccessToken(token);
      localStorage.setItem('access_token', token);
    } catch (error) {
      console.error('Eroare la preluarea tokenului de acces:', error);
    }
  };

  // Preluăm token-ul la montarea componentului, dacă există
  useEffect(() => {
    handleCallback();  // Cheamă callback-ul imediat pentru a obține tokenul
  }, []);

  // Funcție pentru preluarea contactelor
  const fetchContacts = async () => {
    setLoadingContacts(true);
    setNoContactsMessage('');
    try {
      const token = accessToken || localStorage.getItem('access_token');
      console.log('Token de acces:', token);

      if (!token) {
        setNoContactsMessage('Nu s-a putut obține tokenul de acces.');
        return;
      }

      const response = await axios.get('https://graph.microsoft.com/v1.0/me/contacts', {
        headers: {
          Authorization: `Bearer ${token}`,
        },
      });

      console.log(response.data);

      if (response.data.value && response.data.value.length > 0) {
        setContacts(response.data.value);
      } else {
        setNoContactsMessage('Nu sunt contacte disponibile.');
      }
    } catch (error) {
      console.error('Eroare la preluarea contactelor:', error);
      setNoContactsMessage('A apărut o eroare la preluarea contactelor.');
    } finally {
      setLoadingContacts(false);
    }
  };

  // Funcție pentru inițierea unui apel în Microsoft Teams
  const initiateCall = (email) => {
    const teamsLink = `msteams:/l/call/0/0?users=${email}`;
    window.location.href = teamsLink;  // Redirecționează utilizatorul pentru a iniția apelul
  };

  return (
    <div className="teams-container">
      <h1>Microsoft Teams</h1>
      <button onClick={handleLogin}>Conectare la Microsoft Teams</button>
      <button onClick={fetchContacts}>Preia Contactele</button>

      {loadingContacts && <p>Se încarcă contactele...</p>}

      {noContactsMessage && <p>{noContactsMessage}</p>}

      {accessToken && <p>Access Token: {accessToken}</p>}

      <ul>
        {contacts.map(contact => (
          <li key={contact.id}>
            {contact.displayName} - {contact.emailAddresses[0]?.address}
            <button onClick={() => initiateCall(contact.emailAddresses[0]?.address)}>
              Apel audio
            </button>
          </li>
        ))}
      </ul>
    </div>
  );
};

export default MicrosoftTeams;
